protected function getStuffForEngineTypeTable(
    array $currentTable,
    $sumSize,
    $overheadSize
) {
    $formattedSize = '-';
    $unit = '';
    $formattedOverhead = '';
    $overheadUnit = '';
    $tableIsView = false;

    switch ($currentTable['ENGINE']) {
        // MyISAM, ISAM or Heap table: Row count, data size and index size
        // are accurate; data size is accurate for ARCHIVE
        case 'MyISAM':
        case 'ISAM':
        case 'HEAP':
        case 'MEMORY':
        case 'ARCHIVE':
        case 'Aria':
        case 'Maria':
            [
                $currentTable,
                $formattedSize,
                $unit,
                $formattedOverhead,
                $overheadUnit,
                $overheadSize,
                $sumSize,
            ] = $this->getValuesForAriaTable(
                $currentTable,
                $sumSize,
                $overheadSize,
                $formattedSize,
                $unit,
                $formattedOverhead,
                $overheadUnit
            );
            break;
        case 'InnoDB':
        case 'PBMS':
        case 'TokuDB':
        case 'ROCKSDB':
            // InnoDB table: Row count is not accurate but data and index sizes are.
            // PBMS table in Drizzle: TABLE_ROWS is taken from table cache,
            // so it may be unavailable
            [$currentTable, $formattedSize, $unit, $sumSize] = $this->getValuesForInnodbTable(
                $currentTable,
                $sumSize
            );
            break;
        case 'CSV':
            [$currentTable, $formattedSize, $unit, $sumSize] = $this->getValuesForCsvTable(
                $currentTable,
                $sumSize
            );
            break;
        // Mysql 5.0.x (and lower) uses MRG_MyISAM
        // and MySQL 5.1.x (and higher) uses MRG_MYISAM
        // Both are aliases for MERGE
        case 'MRG_MyISAM':
        case 'MRG_MYISAM':
        case 'MERGE':
        case 'BerkeleyDB':
            // Merge or BerkleyDB table: Only row count is accurate.
            if ($this->isShowStats) {
                $formattedSize = ' - ';
                $unit = '';
            }

            break;
        // for a view, the ENGINE is sometimes reported as null,
        // or on some servers it's reported as "SYSTEM VIEW"
        case null:
        case 'SYSTEM VIEW':
            // possibly a view, do nothing
            break;
        case 'Mroonga':
            // The idea is to show the size only if Mroonga is available,
            // in other case the old unknown message will appear
            if (StorageEngine::hasMroongaEngine()) {
                [$currentTable, $formattedSize, $unit, $sumSize] = $this->getValuesForMroongaTable(
                    $currentTable,
                    $sumSize
                );
                break;
            }
            // no break, go to default case
        default:
            // Unknown table type.
            if ($this->isShowStats) {
                $formattedSize = __('unknown');
                $unit = '';
            }
    }

    if ($currentTable['TABLE_TYPE'] === 'VIEW' || $currentTable['TABLE_TYPE'] === 'SYSTEM VIEW') {
        // countRecords() takes care of $cfg['MaxExactCountViews']
        $currentTable['TABLE_ROWS'] = $this->dbi
            ->getTable($this->db, $currentTable['TABLE_NAME'])
            ->countRecords(true);
        $tableIsView = true;
    }

    return [
        $currentTable,
        $formattedSize,
        $unit,
        $formattedOverhead,
        $overheadUnit,
        $overheadSize,
        $tableIsView,
        $sumSize,
    ];
}
